module RefModule (
    input [15:0] data0,
    input [15:0] data1,
    input sel,
    output reg [15:0] data_out
);
  wire [15:0] _tap_data0 = data0 & {16{1'b1}};


always @(*) begin
    case (sel)
        1'b0: data_out = data0;
        1'b1: data_out = data1;
        default: data_out = 16'b0; // Default case (not strictly necessary)
    endcase
end

endmodule
